import pandas as pd
import matplotlib.pyplot as plt
from datetime import datetime
import json

class WorkoutTracker:
    def __init__(self):
        self.workouts = pd.DataFrame(columns=['date', 'sport', 'duration', 'distance', 'heart_rate', 'nutrition'])

    def import_data(self, source, data):
        if source == 'Strava':
            self._import_strava(data)
        elif source == 'Polar Flow':
            self._import_polar(data)
        elif source == 'MyFitnessPal':
            self._import_mfp(data)

    def _import_strava(self, data):
        for entry in data:
            self.workouts = self.workouts.append({
                'date': datetime.strptime(entry['date'], '%Y-%m-%d'),
                'sport': entry['sport'],
                'duration': entry['duration'],
                'distance': entry['distance'],
                'heart_rate': entry['heart_rate'],
                'nutrition': None
            }, ignore_index=True)

    def _import_polar(self, data):
        for entry in data:
            self.workouts = self.workouts.append({
                'date': datetime.strptime(entry['date'], '%Y-%m-%d'),
                'sport': entry['sport'],
                'duration': entry['duration'],
                'distance': entry['distance'],
                'heart_rate': entry['heart_rate'],
                'nutrition': None
            }, ignore_index=True)

    def _import_mfp(self, data):
        for entry in data:
            self.workouts.loc[self.workouts['date'] == datetime.strptime(entry['date'], '%Y-%m-%d'), 'nutrition'] = entry['nutrition']

    def filter_by_sport(self, sport):
        return self.workouts[self.workouts['sport'] == sport]

    def aggregate_heart_rate_zones(self):
        zones = {'rest': 0, 'light': 0, 'moderate': 0, 'hard': 0, 'max': 0}
        for hr in self.workouts['heart_rate']:
            if hr < 120:
                zones['rest'] += 1
            elif hr < 140:
                zones['light'] += 1
            elif hr < 160:
                zones['moderate'] += 1
            elif hr < 180:
                zones['hard'] += 1
            else:
                zones['max'] += 1
        return zones

    def plot_progress(self, metric='pace'):
        if metric == 'pace':
            self.workouts['pace'] = self.workouts['duration'] / self.workouts['distance']
            self.workouts.plot(x='date', y='pace', kind='line', title='Pace Over Time')
        elif metric == 'mileage':
            self.workouts.plot(x='date', y='distance', kind='line', title='Mileage Over Time')
        plt.show()

