        for entry in data:
            self.workouts.loc[self.workouts['date'] == datetime.strptime(entry['date'], '%Y-%m-%d'), 'nutrition'] = entry['nutrition']

    def filter_by_sport(self, sport):
        return self.workouts[self.workouts['sport'] == sport]

    def aggregate_heart_rate_zones(self):
        zones = {'rest': 0, 'light': 0, 'moderate': 0, 'hard': 0, 'max': 0}
        for hr in self.workouts['heart_rate']:
            if hr < 120:
                zones['rest'] += 1
            elif hr < 140:
                zones['light'] += 1
            elif hr < 160:
                zones['moderate'] += 1
            elif hr < 180:
                zones['hard'] += 1
            else:
                zones['max'] += 1
        return zones

