        new_meal = {'date': date, 'meal': meal, 'calories': calories, 'protein': protein, 
                    'carbs': carbs, 'fat': fat}
        self.nutrition = self.nutrition.append(new_meal, ignore_index=True)

    def aggregate_heart_rate(self):
        self.workouts['heart_rate_zone'] = pd.cut(self.workouts['heart_rate'], 
                                                    bins=[0, 120, 140, 160, 180, 200], 
                                                    labels=['Zone 1', 'Zone 2', 'Zone 3', 'Zone 4', 'Zone 5'])
        return self.workouts['heart_rate_zone'].value_counts()

    def plot_progress(self, metric='mileage'):
        if metric not in ['mileage', 'duration']:
            raise ValueError("Metric must be 'mileage' or 'duration'")

        self.workouts['date'] = pd.to_datetime(self.workouts['date'])
        progress = self.workouts.groupby('date')[metric].sum()

        plt.figure(figsize=(10, 5))
        plt.plot(progress.index, progress.values, marker='o')
        plt.title(f'Progress Over Time by {metric.capitalize()}')
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.xticks(rotation=45)
        plt.grid()
        plt.tight_layout()
        plt.show()

    def customize_view(self, view_type='overall'):
        if view_type == 'overall':
            return self.workouts.describe()
        elif view_type == 'mileage':
            return self.workouts.groupby('type')['mileage'].sum()
        else:
            raise ValueError("View type must be 'overall' or 'mileage'")

