import pandas as pd
import matplotlib.pyplot as plt

class ExerciseTracker:
    def __init__(self):
        self.workouts = pd.DataFrame(columns=['date', 'type', 'duration', 'distance', 'heart_rate', 'calories'])
        self.nutrition = pd.DataFrame(columns=['date', 'meal', 'calories', 'protein', 'carbs', 'fat'])

    def add_workout(self, date, workout_type, duration, distance, heart_rate, calories):
        new_workout = {'date': date, 'type': workout_type, 'duration': duration, 'distance': distance, 
                       'heart_rate': heart_rate, 'calories': calories}
        self.workouts = self.workouts.append(new_workout, ignore_index=True)

    def add_nutrition(self, date, meal, calories, protein, carbs, fat):
        new_meal = {'date': date, 'meal': meal, 'calories': calories, 'protein': protein, 
                    'carbs': carbs, 'fat': fat}
        self.nutrition = self.nutrition.append(new_meal, ignore_index=True)

    def aggregate_heart_rate_zones(self):
        zones = {'Zone 1': (0, 60), 'Zone 2': (60, 70), 'Zone 3': (70, 80), 'Zone 4': (80, 90), 'Zone 5': (90, 100)}
        zone_totals = {zone: 0 for zone in zones}

        for hr in self.workouts['heart_rate']:
            for zone, (low, high) in zones.items():
                if low <= hr < high:
                    zone_totals[zone] += 1

        return zone_totals

    def plot_progress(self, metric='mileage'):
        if metric == 'mileage':
            self.workouts['date'] = pd.to_datetime(self.workouts['date'])
            self.workouts.set_index('date', inplace=True)
            self.workouts['cumulative_distance'] = self.workouts['distance'].cumsum()
            self.workouts['cumulative_distance'].plot(title='Cumulative Mileage Over Time')
        elif metric == 'duration':
            self.workouts['cumulative_duration'] = self.workouts['duration'].cumsum()
            self.workouts['cumulative_duration'].plot(title='Cumulative Duration Over Time')

        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.show()

