import pandas as pd
import matplotlib.pyplot as plt
from flask import Flask, render_template, request

app = Flask(__name__)

# Sample data structure for workouts and nutrition
workouts = []
nutrition = []

@app.route('/')
def index():
    return render_template('index.html', workouts=workouts, nutrition=nutrition)

@app.route('/add_workout', methods=['POST'])
def add_workout():
    workout_data = {
        'date': request.form['date'],
        'distance': float(request.form['distance']),
        'duration': float(request.form['duration']),
        'avg_pace': float(request.form['avg_pace']),
        'heart_rate': list(map(int, request.form['heart_rate'].split(',')))
    }
    workouts.append(workout_data)
    return index()

@app.route('/add_nutrition', methods=['POST'])
def add_nutrition():
    nutrition_data = {
        'date': request.form['date'],
        'calories': int(request.form['calories']),
        'protein': int(request.form['protein']),
        'carbs': int(request.form['carbs']),
        'fats': int(request.form['fats'])
    }
    nutrition.append(nutrition_data)
    return index()

@app.route('/progress', methods=['GET'])
def progress():
    if not workouts:
        return "No workout data available."

    df = pd.DataFrame(workouts)
    df['date'] = pd.to_datetime(df['date'])
    df.set_index('date', inplace=True)

    # Calculate total time in different heart rate zones
    heart_rate_zones = {
        'resting': 60,
        'fat_burn': 70,
        'cardio': 80,
        'peak': 90
    }
    zone_time = {zone: 0 for zone in heart_rate_zones}

    for hr in df['heart_rate']:
        for zone, threshold in heart_rate_zones.items():
            zone_time[zone] += sum(1 for h in hr if h < threshold)

    # Plotting progress
    plt.figure(figsize=(10, 5))
    plt.plot(df.index, df['distance'], label='Distance (km)', color='blue')
    plt.plot(df.index, df['avg_pace'], label='Average Pace (min/km)', color='orange')
    plt.title('Workout Progress')
    plt.xlabel('Date')
    plt.ylabel('Metrics')
    plt.legend()
    plt.grid()
    plt.savefig('static/progress.png')
    plt.close()

    return render_template('progress.html', zone_time=zone_time)

if __name__ == '__main__':
    app.run(debug=True)

