        if source not in self.data_sources:
            print("Data source not supported.")
            return

        response = requests.get(self.data_sources[source], headers={'Authorization': f'Bearer {token}'})
        if response.status_code == 200:
            if source == 'Strava':
                self.activities = response.json()
            elif source == 'Polar':
                self.activities = response.json()['activities']
            elif source == 'MyFitnessPal':
                self.nutrition = response.json()['food_entries']
        else:
            print("Failed to fetch data.")

    def customize_dashboard(self, sport=None, calorie_limit=None):
        filtered_activities = self.activities
        if sport:
            filtered_activities = [activity for activity in self.activities if activity['type'] == sport]
        if calorie_limit:
            filtered_activities = [activity for activity in filtered_activities if activity['calories'] <= calorie_limit]

        return filtered_activities

    def plot_progress(self, metric='calories'):
        if metric == 'calories':
            data = [activity['calories'] for activity in self.activities]
        elif metric == 'distance':
            data = [activity['distance'] for activity in self.activities]
        else:
            print("Metric not supported.")
            return

        plt.plot(data)
        plt.title(f'Progress over time ({metric})')
        plt.xlabel('Activity Index')
        plt.ylabel(metric.capitalize())
        plt.show()

    def display_time_in_zones(self):
        time_in_zones = {}
        for activity in self.activities:
            for zone, time in activity['heart_rate_zones'].items():
                if zone not in time_in_zones:
                    time_in_zones[zone] = 0
                time_in_zones[zone] += time

        plt.bar(time_in_zones.keys(), time_in_zones.values())
        plt.title('Time in Heart Rate Zones')
        plt.xlabel('Heart Rate Zone')
        plt.ylabel('Time (minutes)')
        plt.show()

